{!REQUIRESCRIPT("/soap/ajax/25.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/25.0/apex.js")} 

var ContactId= '{!Contact.Id}'; 

var ProSpace = '{!Contact.WebsiteRole__c}'; 

if (ProSpace == '3' || ProSpace == '5'  ){

	var agree = confirm("Are you sure you want to reset the password ?"); 
	if(agree){ 

	var result = sforce.apex.execute("SM015_ResetPassword","ResetPasswod",{ContactId: ContactId}); 

	alert(result); 

	}
}
else {
		alert('This Contact does not have ProSpace Account'); 
}
